InventJournalTrans initJournalTrans(InventJournalTable _inventJournalTable, HDG_InventTransMovJournalCreateContract _contract)
{
    InventJournalTrans inventJournalTrans;

    inventJournalTrans.clear();
    inventJournalTrans.initFromInventJournalTable(_inventJournalTable);
    inventJournalTrans.initFromInventTable(InventTable::find(_contract.parmItemId()));
    inventJournalTrans.TransDate    = _contract.parmTransDate();

    inventJournalTrans.Qty          = _contract.parmQty() * (-1);
    inventJournalTrans.modifyInventJournalTransUnitQty();

    inventJournalTrans.DefaultDimension = _contract.parmDefaultDimension();
    inventJournalTrans.modifiedField(fieldNum(InventJournalTrans, DefaultDimension));

    // Inventory dimension
    inventJournalTrans.InventDimId      = _contract.parmFromInventDimId();

    // If journal type is transfer, insert to To-Inventory dimension
    inventJournalTrans.ToInventDimId    = _contract.parmToInventDimId();

    return inventJournalTrans;
}

public InventJournalName getDefaultJournalName()
{
    if(this.parmJournalNameId())
    {
        return InventJournalName::find(this.parmJournalNameId());
    }
    else
    {
        return InventJournalName::find(InventParameters::find().TransferJournalNameId);
    }
}
